import{_ as e,c as o,ag as i,o as t}from"./chunks/framework.mHuDn-wg.js";const w=JSON.parse('{"title":"PE盘的创建","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/Windows/Windows常见问题.md","filePath":"计算机/Windows/Windows常见问题.md","lastUpdated":null}'),l={name:"计算机/Windows/Windows常见问题.md"};function n(d,a,r,s,h,c){return t(),o("div",null,a[0]||(a[0]=[i('<h1 id="pe盘的创建" tabindex="-1">PE盘的创建 <a class="header-anchor" href="#pe盘的创建" aria-label="Permalink to &quot;PE盘的创建&quot;">​</a></h1><h1 id="启动选项" tabindex="-1">启动选项 <a class="header-anchor" href="#启动选项" aria-label="Permalink to &quot;启动选项&quot;">​</a></h1><p>BIOS界面：del键W</p><p>启动项选择菜单快捷键：在开机时按下，一般是 Esc F8 F9 F11 F12，以及搭配Fn键使用</p><p>打开Windows启动管理器:</p><ul><li>按Win+R键，输入【sysdm.cpl】命令，在系统属性对话框，选择【高级】选项。（也可以右键【此电脑】，点击【属性】，然后选择【高级系统设置】，就可直接导航到系统属性的【高级】选项。）点击【启动和故障恢复】下的【设置（T）……】按钮。在弹出的启动和故障恢复对话框中，勾选【系统启动】下的【显示操作系统列表的时间】选项，再设置一个时间值（比如30秒），然后点击确定即可。如果想关闭Windows启动管理器，只需将【显示操作系统列表的时间】选项取消勾选，或者把时间值改为【0】就可以将Windows启动管理器成功关闭了。</li><li>打开命令行，以管理员身份运行，输入【bcdedit /set {bootmgr} displaybootmenu yes】以及【bcdedit /set {bootmgr} timeout 30】命令（Timeout后跟的数值代表停留在Windows启动管理器页面的秒数，可自由设定），并在每个命令后按Enter键即可开启。</li></ul><p>启动安全模式：</p><ul><li>从Windows 桌面或 Windows 登录屏幕上：按住Shift键，然后单击“重启”按钮，在电脑重启到“选择一个选项”屏幕后，依次选择“疑难解答”&gt;“高级选项”&gt;“启动设置”&gt;“重启”</li><li>打开设置&gt;更新和安&gt;恢复，在“高级启动”部分下，单击“立即重新启动”按钮，接下来同上</li><li>按 Windows 键 + R 打开”运行“框，键入 ”msconfig“（系统配置），单击“引导”选项卡，在“引导选项”部分下，选中“安全引导”选项，选中“最小”选项</li><li>通过Windows启动管理器： 在Windows启动管理器菜单中，按F8键以访问“启动设置”菜单选项，选择要启动的安全模式环境之一即可</li></ul><h1 id="忘记window登录密码" tabindex="-1">忘记window登录密码 <a class="header-anchor" href="#忘记window登录密码" aria-label="Permalink to &quot;忘记window登录密码&quot;">​</a></h1><p>进入PE，解锁</p><h1 id="系统崩溃" tabindex="-1">系统崩溃 <a class="header-anchor" href="#系统崩溃" aria-label="Permalink to &quot;系统崩溃&quot;">​</a></h1><h1 id="系统安装" tabindex="-1">系统安装 <a class="header-anchor" href="#系统安装" aria-label="Permalink to &quot;系统安装&quot;">​</a></h1><ul><li>在一台电脑上<a href="https://www.microsoft.com/zh-cn/software-download/windows10" target="_blank" rel="noreferrer">下载 Windows 10 (microsoft.com)</a>，运行并安装在一个空U盘上即可安装</li><li>通过PE安装</li></ul><h1 id="禁用自动更新" tabindex="-1">禁用自动更新 <a class="header-anchor" href="#禁用自动更新" aria-label="Permalink to &quot;禁用自动更新&quot;">​</a></h1><p>更改注册表目录：计算机\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\WindowsUpdate\\UX\\Settings 新建DWORD，重命名为FlightSettingsMaxPauseDays，十进制，10000</p><h1 id="macosx文件夹" tabindex="-1">_MACOSX文件夹 <a class="header-anchor" href="#macosx文件夹" aria-label="Permalink to &quot;\\_MACOSX文件夹&quot;">​</a></h1><p>在解压一个ZIP压缩包时，有时解压后会多了产生一个名为<code>_MACOSX</code>、<code>.DS_Store</code> 等 macOS 系统隐藏文件夹、文件，这是因为：在Mac系统上压缩文件时，会自动将一些缓存的内容一起压缩，而这些在Mac系统中是不可见的，只有在Windows系统中解压后才能看到。简而言之，<strong>_MACOSX在Windows中是垃圾文件，可以直接删除，对压缩包本身的文件是没有什么影响的</strong>。</p><h1 id="存储设备弹出" tabindex="-1">存储设备弹出 <a class="header-anchor" href="#存储设备弹出" aria-label="Permalink to &quot;存储设备弹出&quot;">​</a></h1><p>事件查看器-&gt;占用程序和id 磁盘管理-&gt;脱机</p><h2 id="文件缩略图" tabindex="-1">文件缩略图 <a class="header-anchor" href="#文件缩略图" aria-label="Permalink to &quot;文件缩略图&quot;">​</a></h2><ul><li>问题: Windows资源管理器不能预览文件</li><li>缩略图预览：高级系统设置-&gt;（性能）设置-&gt;（视觉效果）勾选“显示缩略图，而不是显示图标”</li></ul>',21)]))}const p=e(l,[["render",n]]);export{w as __pageData,p as default};
